            .s => switch (c) {
                '"'  => { _st = .q; },
                ','  => { _row.append(_pa, "") catch {}; },
                '\r' => {},
                '\n' => { if (_row.items.len > 0) { _rows.append(_pa, _row.toOwnedSlice(_pa) catch &.{}) catch {}; _row = .{}; } },
                else => { _f.append(_pa, c) catch {}; _st = .fld; },
